SELECT "t0"."$f0" AS "H8_30_TO_9", "t2"."$f0" AS "H9_TO_9_30", "t4"."$f0" AS "H9_30_TO_10", "t6"."$f0" AS "H10_TO_10_30", "t8"."$f0" AS "H10_30_TO_11", "t10"."$f0" AS "H11_TO_11_30", "t12"."$f0" AS "H11_30_TO_12", "t14"."$f0" AS "H12_TO_12_30"
FROM (SELECT COUNT(*) AS "$f0"
FROM "tpcds"."STORE_SALES",
"tpcds"."HOUSEHOLD_DEMOGRAPHICS",
"tpcds"."TIME_DIM",
"tpcds"."STORE"
WHERE "STORE_SALES"."SS_SOLD_TIME_SK" = "TIME_DIM"."T_TIME_SK" AND ("STORE_SALES"."SS_HDEMO_SK" = "HOUSEHOLD_DEMOGRAPHICS"."HD_DEMO_SK" AND "STORE_SALES"."SS_STORE_SK" = "STORE"."S_STORE_SK") AND ("TIME_DIM"."T_HOUR" = 8 AND "TIME_DIM"."T_MINUTE" >= 30 AND (("HOUSEHOLD_DEMOGRAPHICS"."HD_DEP_COUNT" = 4 AND "HOUSEHOLD_DEMOGRAPHICS"."HD_VEHICLE_COUNT" <= 4 + 2 OR "HOUSEHOLD_DEMOGRAPHICS"."HD_DEP_COUNT" = 2 AND "HOUSEHOLD_DEMOGRAPHICS"."HD_VEHICLE_COUNT" <= 2 + 2 OR "HOUSEHOLD_DEMOGRAPHICS"."HD_DEP_COUNT" = 0 AND "HOUSEHOLD_DEMOGRAPHICS"."HD_VEHICLE_COUNT" <= 2) AND "STORE"."S_STORE_NAME" = 'ese'))) AS "t0",
(SELECT COUNT(*) AS "$f0"
FROM "tpcds"."STORE_SALES" AS "STORE_SALES0",
"tpcds"."HOUSEHOLD_DEMOGRAPHICS" AS "HOUSEHOLD_DEMOGRAPHICS0",
"tpcds"."TIME_DIM" AS "TIME_DIM0",
"tpcds"."STORE" AS "STORE0"
WHERE "STORE_SALES0"."SS_SOLD_TIME_SK" = "TIME_DIM0"."T_TIME_SK" AND ("STORE_SALES0"."SS_HDEMO_SK" = "HOUSEHOLD_DEMOGRAPHICS0"."HD_DEMO_SK" AND "STORE_SALES0"."SS_STORE_SK" = "STORE0"."S_STORE_SK") AND ("TIME_DIM0"."T_HOUR" = 9 AND "TIME_DIM0"."T_MINUTE" < 30 AND (("HOUSEHOLD_DEMOGRAPHICS0"."HD_DEP_COUNT" = 4 AND "HOUSEHOLD_DEMOGRAPHICS0"."HD_VEHICLE_COUNT" <= 4 + 2 OR "HOUSEHOLD_DEMOGRAPHICS0"."HD_DEP_COUNT" = 2 AND "HOUSEHOLD_DEMOGRAPHICS0"."HD_VEHICLE_COUNT" <= 2 + 2 OR "HOUSEHOLD_DEMOGRAPHICS0"."HD_DEP_COUNT" = 0 AND "HOUSEHOLD_DEMOGRAPHICS0"."HD_VEHICLE_COUNT" <= 2) AND "STORE0"."S_STORE_NAME" = 'ese'))) AS "t2",
(SELECT COUNT(*) AS "$f0"
FROM "tpcds"."STORE_SALES" AS "STORE_SALES1",
"tpcds"."HOUSEHOLD_DEMOGRAPHICS" AS "HOUSEHOLD_DEMOGRAPHICS1",
"tpcds"."TIME_DIM" AS "TIME_DIM1",
"tpcds"."STORE" AS "STORE1"
