(SELECT COUNT(*) AS "$f0"
FROM "tpcds"."STORE_SALES" AS "STORE_SALES2",
"tpcds"."HOUSEHOLD_DEMOGRAPHICS" AS "HOUSEHOLD_DEMOGRAPHICS2",
"tpcds"."TIME_DIM" AS "TIME_DIM2",
"tpcds"."STORE" AS "STORE2"
