"tpcds"."HOUSEHOLD_DEMOGRAPHICS" AS "HOUSEHOLD_DEMOGRAPHICS4",
"tpcds"."TIME_DIM" AS "TIME_DIM4",
"tpcds"."STORE" AS "STORE4"
