(SELECT COUNT(*) AS "$f0"
FROM "tpcds"."STORE_SALES" AS "STORE_SALES6",
"tpcds"."HOUSEHOLD_DEMOGRAPHICS" AS "HOUSEHOLD_DEMOGRAPHICS6",
"tpcds"."TIME_DIM" AS "TIME_DIM6",
"tpcds"."STORE" AS "STORE6"
WHERE "STORE_SALES6"."SS_SOLD_TIME_SK" = "TIME_DIM6"."T_TIME_SK" AND ("STORE_SALES6"."SS_HDEMO_SK" = "HOUSEHOLD_DEMOGRAPHICS6"."HD_DEMO_SK" AND "STORE_SALES6"."SS_STORE_SK" = "STORE6"."S_STORE_SK") AND ("TIME_DIM6"."T_HOUR" = 12 AND "TIME_DIM6"."T_MINUTE" < 30 AND (("HOUSEHOLD_DEMOGRAPHICS6"."HD_DEP_COUNT" = 4 AND "HOUSEHOLD_DEMOGRAPHICS6"."HD_VEHICLE_COUNT" <= 4 + 2 OR "HOUSEHOLD_DEMOGRAPHICS6"."HD_DEP_COUNT" = 2 AND "HOUSEHOLD_DEMOGRAPHICS6"."HD_VEHICLE_COUNT" <= 2 + 2 OR "HOUSEHOLD_DEMOGRAPHICS6"."HD_DEP_COUNT" = 0 AND "HOUSEHOLD_DEMOGRAPHICS6"."HD_VEHICLE_COUNT" <= 2) AND "STORE6"."S_STORE_NAME" = 'ese'))) AS "t14"
